import { Component, computed, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ReactiveFormsModule, FormBuilder, Validators } from '@angular/forms';
import { RouterLink, ActivatedRoute, Router } from '@angular/router';
import { toSignal } from '@angular/core/rxjs-interop';
import { INDUSTRIES } from '../../models/models';

@Component({
  selector: 'app-account-form',
  standalone: true,
  imports: [CommonModule, ReactiveFormsModule, RouterLink],
  templateUrl: './account-form.component.html',
  styleUrl: './accounts.css',
})
export class AccountFormComponent {
  private fb = inject(FormBuilder);
  private route = inject(ActivatedRoute);
  private router = inject(Router);

  readonly industries = INDUSTRIES;
  private pm = toSignal(this.route.paramMap, { initialValue: this.route.snapshot.paramMap });
  readonly editId = computed(() => this.pm().get('id'));
  readonly isEdit = computed(() => !!this.editId());

  form = this.fb.group({
    name: ['', [Validators.required]],
    industry: ['Technology', [Validators.required]],
    website: [''],
    phone: [''],
    city: [''],
    employees: [0, [Validators.min(0)]],
    annualRevenue: [0, [Validators.min(0)]],
  });

  constructor() {
    if (this.isEdit()) {
      // Prefill with representative existing values for the mockup.
      this.form.patchValue({
        name: 'Acme Corporation',
        industry: 'Manufacturing',
        website: 'acme.com',
        phone: '+1 415 555 0100',
        city: 'San Francisco',
        employees: 4200,
        annualRevenue: 320000000,
      });
    }
  }

  save(): void {
    if (this.form.invalid) {
      this.form.markAllAsTouched();
      return;
    }
    const target = this.isEdit() ? ['/accounts', this.editId()] : ['/accounts'];
    this.router.navigate(target);
  }

  cancel(): void {
    this.router.navigate(this.isEdit() ? ['/accounts', this.editId()] : ['/accounts']);
  }
}
